#include<bits/stdc++.h>
using namespace std;
int main(void){
	priority_queue<double,vector<double>,greater<double> >q[2];
	double x;
	int t,n,flag[10005];
	cin>>t;
	while(t--){
		cin>>n;
		for(int i=0;i<n;i++)cin>>flag[i];
		for(int i=0;i<n;i++){cin>>x;q[flag[i]].push(x);}
		for(int i=0;i<2;i++){
			while(q[i].size()){
				cout<<q[i].top()<<' ';
				q[i].pop();
			}
			cout<<endl;
		}
	}
	return false;
}
